const pptxgen = require("pptxgenjs");
const React = require("react");
const ReactDOMServer = require("react-dom/server");
const sharp = require("sharp");

// ─── Color Palette (Midnight Executive + Warm Signal) ───────────────────────
const C = {
  navy:    "1B2A4A",   // primary dark
  navyMid: "243655",   // slide backgrounds
  teal:    "0D7E8A",   // accent / call-to-action
  tealLt:  "14A0B0",   // hover teal
  gold:    "D4A843",   // warning / highlight
  red:     "C0392B",   // risk / danger
  green:   "1A7F5A",   // positive / success
  white:   "FFFFFF",
  offWht:  "F4F6F9",
  gray1:   "E8ECF2",
  gray2:   "B0BEC5",
  gray3:   "607080",
  gray4:   "3D4F60",
  ltBlue:  "D6E4F0",
  accent:  "F0C040",   // bright accent for callouts
};

// ─── Icon helpers ─────────────────────────────────────────────────────────────
const {
  FaExclamationTriangle, FaChartLine, FaUsers, FaCogs,
  FaCheckCircle, FaArrowRight, FaLightbulb, FaShieldAlt,
  FaBullseye, FaDatabase, FaRocket, FaCalendarAlt,
  FaMoneyBillWave, FaHeartbeat, FaTrophy, FaSearch,
  FaUserTie, FaStar, FaClipboardList, FaProjectDiagram,
  FaBrain, FaChartBar, FaFlask, FaFlag
} = require("react-icons/fa");

async function iconPng(IconComp, color = "#FFFFFF", size = 256) {
  const svg = ReactDOMServer.renderToStaticMarkup(
    React.createElement(IconComp, { color, size: String(size) })
  );
  const buf = await sharp(Buffer.from(svg)).png().toBuffer();
  return "image/png;base64," + buf.toString("base64");
}

// ─── Slide helpers ─────────────────────────────────────────────────────────────
function addSlideHeader(slide, pres, title, subtitle = null, darkBg = false) {
  const bgColor = darkBg ? C.navy : C.offWht;
  const titleColor = darkBg ? C.white : C.navy;
  const subColor = darkBg ? C.gray2 : C.gray3;

  // Top accent bar
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 0, w: 10, h: 0.08,
    fill: { color: C.teal }, line: { color: C.teal }
  });

  // Title
  slide.addText(title, {
    x: 0.45, y: 0.15, w: 8.5, h: 0.55,
    fontSize: 22, bold: true, color: titleColor,
    fontFace: "Calibri", margin: 0
  });

  if (subtitle) {
    slide.addText(subtitle, {
      x: 0.45, y: 0.68, w: 8.5, h: 0.28,
      fontSize: 11, color: subColor, fontFace: "Calibri", margin: 0
    });
  }

  // Bottom footer bar
  slide.addShape(pres.shapes.RECTANGLE, {
    x: 0, y: 5.45, w: 10, h: 0.175,
    fill: { color: C.navy }, line: { color: C.navy }
  });
  slide.addText("LG PRI HR실 / EXG팀  ·  2026.03  ·  Confidential", {
    x: 0.4, y: 5.46, w: 7, h: 0.16,
    fontSize: 8, color: C.gray2, fontFace: "Calibri", margin: 0
  });
}

function card(slide, pres, x, y, w, h, opts = {}) {
  const { fill = C.white, shadow = true, radius = false } = opts;
  const shapeType = radius ? pres.shapes.ROUNDED_RECTANGLE : pres.shapes.RECTANGLE;
  slide.addShape(shapeType, {
    x, y, w, h,
    fill: { color: fill },
    line: { color: C.gray1, width: 0.5 },
    ...(radius && { rectRadius: 0.08 }),
    ...(shadow && {
      shadow: { type: "outer", color: "000000", blur: 8, offset: 2, angle: 135, opacity: 0.10 }
    })
  });
}

function statCallout(slide, pres, x, y, w, h, number, label, color = C.teal, bgColor = C.white) {
  card(slide, pres, x, y, w, h, { fill: bgColor });
  slide.addShape(pres.shapes.RECTANGLE, {
    x, y, w: 0.06, h,
    fill: { color }, line: { color }
  });
  slide.addText(number, {
    x: x + 0.15, y: y + 0.12, w: w - 0.2, h: h * 0.52,
    fontSize: 32, bold: true, color, fontFace: "Calibri",
    align: "center", margin: 0
  });
  slide.addText(label, {
    x: x + 0.1, y: y + h * 0.55, w: w - 0.15, h: h * 0.38,
    fontSize: 9.5, color: C.gray3, fontFace: "Calibri",
    align: "center", margin: 0, wrap: true
  });
}

// ═══════════════════════════════════════════════════════════════════════════════
async function buildPresentation() {
  const pres = new pptxgen();
  pres.layout = "LAYOUT_16x9";
  pres.title = "AX 기반 Pulse Check — 경영진 보고";

  // ─────────────────────────────────────────────────────────────────────────
  // SLIDE 1: COVER (dark)
  // ─────────────────────────────────────────────────────────────────────────
  {
    const s = pres.addSlide();
    s.background = { color: C.navy };

    // Geometric accent shapes (top-right corner)
    s.addShape(pres.shapes.RECTANGLE, {
      x: 7.2, y: -0.05, w: 2.85, h: 5.9,
      fill: { color: C.navyMid }, line: { color: C.navyMid }
    });
    s.addShape(pres.shapes.RECTANGLE, {
      x: 9.3, y: -0.05, w: 0.75, h: 5.9,
      fill: { color: C.teal, transparency: 30 }, line: { color: C.teal }
    });
    // Horizontal gold accent
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.45, y: 1.55, w: 3.2, h: 0.055,
      fill: { color: C.gold }, line: { color: C.gold }
    });

    s.addText("AX 기반 Pulse Check", {
      x: 0.45, y: 0.7, w: 6.5, h: 0.75,
      fontSize: 38, bold: true, color: C.white,
      fontFace: "Calibri", margin: 0
    });
    s.addText("체계 구축", {
      x: 0.45, y: 1.4, w: 6.5, h: 0.7,
      fontSize: 38, bold: true, color: C.tealLt,
      fontFace: "Calibri", margin: 0
    });
    s.addText("직원경험(EX)을 실시간으로 감지하고, 선제적으로 대응하는\nAX 기반 조직 건강도 상시 측정 시스템 구축 제안", {
      x: 0.45, y: 1.75, w: 6.5, h: 0.75,
      fontSize: 13, color: C.gray2, fontFace: "Calibri",
      margin: 0, lineSpacingMultiple: 1.35
    });

    // Key metrics preview
    const stats = [
      ["연 1회", "현행 진단 주기"],
      ["월 1회", "Pulse Check 전환"],
      ["~8주", "이슈 발견 선행 효과"],
    ];
    stats.forEach(([num, lbl], i) => {
      s.addText(num, {
        x: 0.45 + i * 2.05, y: 2.75, w: 1.85, h: 0.5,
        fontSize: 22, bold: true, color: C.gold, fontFace: "Calibri",
        margin: 0
      });
      s.addText(lbl, {
        x: 0.45 + i * 2.05, y: 3.22, w: 1.85, h: 0.28,
        fontSize: 9, color: C.gray2, fontFace: "Calibri", margin: 0
      });
    });
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.45, y: 2.68, w: 6.3, h: 0.04,
      fill: { color: C.gray4 }, line: { color: C.gray4 }
    });
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.45, y: 3.52, w: 6.3, h: 0.04,
      fill: { color: C.gray4 }, line: { color: C.gray4 }
    });

    s.addText("PRI HR실 / EXG팀   |   2026. 03. 10.   |   Strictly Confidential", {
      x: 0.45, y: 4.7, w: 6.5, h: 0.25,
      fontSize: 9.5, color: C.gray3, fontFace: "Calibri", margin: 0
    });

    // Table of contents sidebar
    const agenda = [
      "Executive Summary",
      "문제의 크기와 비용",
      "Pulse Check 해법",
      "설문 설계 & 측정 체계",
      "Communication & Dashboard",
      "ROI & 기대 성과",
      "파일럿 → 전사 확산 로드맵",
      "리스크 관리 & 경영진 결정 사항",
    ];
    s.addShape(pres.shapes.RECTANGLE, {
      x: 7.25, y: 0, w: 2.75, h: 5.625,
      fill: { color: C.navyMid }, line: { color: C.navyMid }
    });
    s.addText("목  차", {
      x: 7.35, y: 0.25, w: 2.5, h: 0.35,
      fontSize: 11, bold: true, color: C.tealLt, fontFace: "Calibri", margin: 0
    });
    agenda.forEach((item, i) => {
      s.addShape(pres.shapes.OVAL, {
        x: 7.35, y: 0.73 + i * 0.58, w: 0.22, h: 0.22,
        fill: { color: i === 0 ? C.teal : C.gray4 }, line: { color: "000000", width: 0 }
      });
      s.addText(`${i + 1}`, {
        x: 7.35, y: 0.73 + i * 0.58, w: 0.22, h: 0.22,
        fontSize: 7, bold: true, color: C.white, align: "center", valign: "middle",
        fontFace: "Calibri", margin: 0
      });
      s.addText(item, {
        x: 7.62, y: 0.72 + i * 0.58, w: 2.2, h: 0.24,
        fontSize: 9, color: C.gray2, fontFace: "Calibri", margin: 0
      });
    });
  }

  // ─────────────────────────────────────────────────────────────────────────
  // SLIDE 2: EXECUTIVE SUMMARY (SCR 구조)
  // ─────────────────────────────────────────────────────────────────────────
  {
    const s = pres.addSlide();
    s.background = { color: C.offWht };
    addSlideHeader(s, pres, "Executive Summary", "Situation · Complication · Resolution");

    // SCR three columns
    const cols = [
      {
        tag: "Situation",
        color: C.navy,
        title: "우리는 지금 '과거'를 보고 있습니다",
        body: [
          "LG PRI는 연 1회 LG Way Survey로 조직 건강도를 진단합니다.",
          "진단→분석→결과 공유까지 평균 6~8주가 소요됩니다.",
          "그 사이 번아웃과 이탈은 이미 진행되고 있습니다.",
        ]
      },
      {
        tag: "Complication",
        color: C.red,
        title: "실시간 이슈를 연 1회 데이터로 감지할 수 없습니다",
        body: [
          "AX 전환기, 리더 교체기, 프로젝트 과부하 시점의 조직 변화가 데이터에 포착되지 않습니다.",
          "이직 결정은 평균 이직 3~4개월 전에 완료됩니다.*",
          "글로벌 선도 제조사는 이미 월간 Pulse Check로 전환 중입니다.",
        ]
      },
      {
        tag: "Resolution",
        color: C.teal,
        title: "AX 기반 월간 Pulse Check로 선제 대응합니다",
        body: [
          "8개 EX 문항을 월 1회 측정, AI가 이상 신호를 자동 감지합니다.",
          "구성원·리더·경영진 각 계층에 맞춤형 Action을 제공합니다.",
          "Q4 파일럿 후 전사 확산, 이탈 비용 연간 수억 원 절감을 기대합니다.",
        ]
      }
    ];

    cols.forEach((col, i) => {
      const x = 0.35 + i * 3.15;
      const w = 3.0;

      // Tag label
      s.addShape(pres.shapes.RECTANGLE, {
        x, y: 0.98, w, h: 0.32,
        fill: { color: col.color }, line: { color: col.color }
      });
      s.addText(col.tag, {
        x, y: 0.98, w, h: 0.32,
        fontSize: 11, bold: true, color: C.white, align: "center",
        fontFace: "Calibri", margin: 0, valign: "middle"
      });

      // Card
      card(s, pres, x, 1.3, w, 3.75, { fill: C.white });

      s.addText(col.title, {
        x: x + 0.15, y: 1.4, w: w - 0.25, h: 0.62,
        fontSize: 11, bold: true, color: col.color,
        fontFace: "Calibri", margin: 0, wrap: true, lineSpacingMultiple: 1.3
      });
      s.addShape(pres.shapes.RECTANGLE, {
        x: x + 0.12, y: 2.02, w: w - 0.28, h: 0.03,
        fill: { color: C.gray1 }, line: { color: C.gray1 }
      });
      col.body.forEach((line, j) => {
        s.addShape(pres.shapes.RECTANGLE, {
          x: x + 0.15, y: 2.16 + j * 0.78, w: 0.05, h: 0.55,
          fill: { color: col.color }, line: { color: col.color }
        });
        s.addText(line, {
          x: x + 0.27, y: 2.14 + j * 0.78, w: w - 0.42, h: 0.62,
          fontSize: 10, color: C.gray4, fontFace: "Calibri",
          margin: 0, wrap: true, lineSpacingMultiple: 1.3
        });
      });
    });

    // Bottom key message
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.35, y: 5.1, w: 9.3, h: 0.3,
      fill: { color: C.navy }, line: { color: C.navy }
    });
    s.addText("★  핵심 메시지 : 지금 이 순간 조직에서 무슨 일이 일어나고 있는지 — HR이 먼저 알고, 경영진이 먼저 대응합니다.", {
      x: 0.35, y: 5.1, w: 9.3, h: 0.3,
      fontSize: 10.5, bold: true, color: C.gold, align: "center",
      fontFace: "Calibri", margin: 0, valign: "middle"
    });

    s.addText("* 출처: Gallup State of the Global Workplace 2024", {
      x: 0.35, y: 5.18, w: 5, h: 0.2,
      fontSize: 7.5, color: C.gray3, fontFace: "Calibri", margin: 0
    });
  }

  // ─────────────────────────────────────────────────────────────────────────
  // SLIDE 3: 문제의 크기와 비용
  // ─────────────────────────────────────────────────────────────────────────
  {
    const s = pres.addSlide();
    s.background = { color: C.offWht };
    addSlideHeader(s, pres, "문제의 크기 : 연 1회 진단이 만들어내는 비용", "현행 체계의 구조적 한계와 그 경영적 파급 효과");

    // 3 problem cards top
    const problems = [
      {
        num: "① Time Lag",
        desc: "진단→결과 공유까지 6~8주",
        impact: "번아웃·이탈 후 데이터 도달",
        color: C.red
      },
      {
        num: "② Static Snapshot",
        desc: "연 1회, 단 하나의 데이터 포인트",
        impact: "계절·리더 교체·AX 충격 미포착",
        color: C.gold
      },
      {
        num: "③ Action Gap",
        desc: "리포트가 행동 변화로 이어지지 않음",
        impact: "팀별 맞춤 솔루션 제공 불가",
        color: C.navy
      }
    ];

    problems.forEach((p, i) => {
      const x = 0.35 + i * 3.15;
      card(s, pres, x, 0.98, 3.0, 1.55, { fill: C.white });
      s.addShape(pres.shapes.RECTANGLE, {
        x, y: 0.98, w: 0.07, h: 1.55,
        fill: { color: p.color }, line: { color: p.color }
      });
      s.addText(p.num, {
        x: x + 0.15, y: 1.04, w: 2.75, h: 0.32,
        fontSize: 11, bold: true, color: p.color, fontFace: "Calibri", margin: 0
      });
      s.addText(p.desc, {
        x: x + 0.15, y: 1.35, w: 2.75, h: 0.3,
        fontSize: 10, color: C.gray4, fontFace: "Calibri", margin: 0, wrap: true
      });
      s.addText("▶ " + p.impact, {
        x: x + 0.15, y: 1.65, w: 2.75, h: 0.28,
        fontSize: 9.5, color: C.gray3, italic: true, fontFace: "Calibri",
        margin: 0, wrap: true
      });
    });

    // Cost estimation section
    s.addText("비용 추정 : LG PRI 규모 기준 (연간)", {
      x: 0.35, y: 2.7, w: 5, h: 0.3,
      fontSize: 12, bold: true, color: C.navy, fontFace: "Calibri", margin: 0
    });

    // stat boxes
    const costStats = [
      { num: "₩1.2억~", label: "직원 1인 이탈 시\n대체 비용 추정*", color: C.red },
      { num: "17%↓", label: "몰입도 하위 조직의\n생산성 손실 (Gallup)", color: C.gold },
      { num: "43%↓", label: "몰입도 상위 조직 대비\n이직률 감소 (Gallup)", color: C.green },
      { num: "~8주", label: "현행 이슈 감지까지\n평균 소요 시간", color: C.teal },
    ];
    costStats.forEach((st, i) => {
      statCallout(s, pres, 0.35 + i * 2.35, 3.08, 2.15, 1.28, st.num, st.label, st.color);
    });

    s.addText("* 이탈 비용 = 채용광고 + 인터뷰 시간 + 온보딩 + 숙련도 회복 기간 인건비 합산 추정치 (연봉 1배 내외)", {
      x: 0.35, y: 4.42, w: 9, h: 0.2,
      fontSize: 7.5, color: C.gray3, italic: true, fontFace: "Calibri", margin: 0
    });

    // Timeline gap visualization
    s.addText("현행 vs. Pulse Check : 이슈 감지 속도 비교", {
      x: 0.35, y: 4.65, w: 5, h: 0.25,
      fontSize: 10, bold: true, color: C.navy, fontFace: "Calibri", margin: 0
    });
    const tl = [
      { label: "이슈 발생", x: 0.5 },
      { label: "LG Way 진단", x: 2.8 },
      { label: "결과 공개", x: 5.5 },
      { label: "대응 시작", x: 7.8 },
    ];
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.5, y: 5.08, w: 7.5, h: 0.06,
      fill: { color: C.red, transparency: 30 }, line: { color: C.red }
    });
    tl.forEach((t) => {
      s.addShape(pres.shapes.OVAL, {
        x: t.x - 0.07, y: 5.02, w: 0.18, h: 0.18,
        fill: { color: C.red }, line: { color: C.red }
      });
      s.addText(t.label, {
        x: t.x - 0.4, y: 5.21, w: 1.1, h: 0.2,
        fontSize: 7.5, color: C.gray3, align: "center", fontFace: "Calibri", margin: 0
      });
    });
    s.addShape(pres.shapes.RECTANGLE, {
      x: 0.5, y: 4.88, w: 1.4, h: 0.06,
      fill: { color: C.teal }, line: { color: C.teal }
    });
    s.addText("Pulse: 이슈→감지 4주", {
      x: 0.5, y: 4.72, w: 2, h: 0.18,
      fontSize: 8, bold: true, color: C.teal, fontFace: "Calibri", margin: 0
    });
  }

  // ─────────────────────────────────────────────────────────────────────────
  // SLIDE 4: Pulse Check 해법 — Mechanism
  // ─────────────────────────────────────────────────────────────────────────
  {
    const s = pres.addSlide();
    s.background = { color: C.offWht };
    addSlideHeader(s, pres, "Pulse Check 해법 : 작동 원리 (Mechanism)", "SDT · LMX 이론 기반의 EX 측정 → 성과 선순환 구조");

    // Flow: EX → Engagement → Performance
    const flowItems = [
      { label: "조직 지원\n& 심리 안전", sub: "자율성·성장·관계·환경", color: C.teal, x: 0.35 },
      { label: "직무 몰입\n(Engagement)", sub: "eNPS·감정온도·Job-Fit", color: C.navy, x: 3.4 },
      { label: "조직 성과\n(Performance)", sub: "생산성·이탈률·AX Maturity", color: C.green, x: 6.45 },
    ];

    flowItems.forEach((f, i) => {
      card(s, pres, f.x, 1.0, 2.7, 1.3, { fill: f.color });
      s.addText(f.label, {
        x: f.x, y: 1.05, w: 2.7, h: 0.72,
        fontSize: 13, bold: true, color: C.white, align: "center",
        fontFace: "Calibri", margin: 0, valign: "middle", wrap: true,
        lineSpacingMultiple: 1.3
      });
      s.addText(f.sub, {
        x: f.x, y: 1.75, w: 2.7, h: 0.3,
        fontSize: 9, color: i === 1 ? C.ltBlue : C.gray1, align: "center",
        fontFace: "Calibri", margin: 0
      });
      if (i < 2) {
        s.addText("▶", {
          x: f.x + 2.72, y: 1.45, w: 0.65, h: 0.4,
          fontSize: 22, color: C.gold, align: "center",
          fontFace: "Calibri", margin: 0, valign: "middle"
        });
      }
    });

    // 3-layer system explanation
    s.addText("3계층 측정 → 감지 → 대응 구조", {
      x: 0.35, y: 2.5, w: 6, h: 0.3,
      fontSize: 12, bold: true, color: C.navy, fontFace: "Calibri", margin: 0
    });

    const layers = [
      {
        layer: "Layer 1", name: "월간 Pulse 측정", color: C.teal,
