const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle, WidthType,
  ShadingType, VerticalAlign, PageNumber, LevelFormat, PageBreak,
  TabStopType, TabStopPosition
} = require("docx");
const fs = require("fs");

// ── 색상 팔레트 ──────────────────────────────────────────────────────────────
const COLOR = {
  navy:   "1B2A4A",
  teal:   "0D7E8A",
  gold:   "C49A1A",
  red:    "C0392B",
  green:  "1A7F5A",
  gray1:  "F4F6F9",
  gray2:  "B0BEC5",
  gray3:  "607080",
  white:  "FFFFFF",
  ltBlue: "D6E4F0",
};

// ── 헬퍼 함수 ─────────────────────────────────────────────────────────────────
const border = (color = "CCCCCC", size = 4) => ({
  style: BorderStyle.SINGLE, size, color
});
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const allBorders = (c = "CCCCCC", s = 4) => ({
  top: border(c, s), bottom: border(c, s),
  left: border(c, s), right: border(c, s)
});
const cellMargins = { top: 80, bottom: 80, left: 150, right: 150 };

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 400, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 8, color: COLOR.teal, space: 4 } },
    children: [new TextRun({ text, font: "Arial", size: 32, bold: true, color: COLOR.navy })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 280, after: 80 },
    children: [new TextRun({ text, font: "Arial", size: 26, bold: true, color: COLOR.teal })]
  });
}

function h3(text) {
  return new Paragraph({
    spacing: { before: 200, after: 60 },
    children: [new TextRun({ text, font: "Arial", size: 22, bold: true, color: COLOR.navy })]
  });
}

function body(text, opts = {}) {
  return new Paragraph({
    spacing: { before: 60, after: 60, line: 276 },
    children: [new TextRun({
      text, font: "Arial", size: 21,
      color: opts.color || "2C3E50",
      bold: opts.bold || false,
      italics: opts.italic || false,
    })]
  });
}

function bullet(text, level = 0, color = COLOR.navy) {
  return new Paragraph({
    numbering: { reference: "bullets", level },
    spacing: { before: 40, after: 40, line: 260 },
    children: [new TextRun({ text, font: "Arial", size: 20, color: "2C3E50" })]
  });
}

function spacer(before = 120) {
  return new Paragraph({ spacing: { before, after: 0 }, children: [new TextRun("")] });
}

function divider(color = COLOR.teal) {
  return new Paragraph({
    spacing: { before: 120, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 6, color, space: 1 } },
    children: [new TextRun("")]
  });
}

function calloutBox(label, text, bgColor = COLOR.ltBlue, labelColor = COLOR.navy) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [1200, 8160],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            width: { size: 1200, type: WidthType.DXA },
            shading: { fill: COLOR.navy, type: ShadingType.CLEAR },
            margins: cellMargins,
            verticalAlign: VerticalAlign.CENTER,
            borders: allBorders(COLOR.navy, 0),
            children: [new Paragraph({
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: label, font: "Arial", size: 18, bold: true, color: COLOR.white })]
            })]
          }),
          new TableCell({
            width: { size: 8160, type: WidthType.DXA },
            shading: { fill: bgColor, type: ShadingType.CLEAR },
            margins: cellMargins,
            borders: allBorders(bgColor, 0),
            children: [new Paragraph({
              children: [new TextRun({ text, font: "Arial", size: 20, color: "2C3E50" })]
            })]
          }),
        ]
      })
    ]
  });
}

function highlightBox(text, bgColor = COLOR.navy, textColor = COLOR.white) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            width: { size: 9360, type: WidthType.DXA },
            shading: { fill: bgColor, type: ShadingType.CLEAR },
            margins: { top: 120, bottom: 120, left: 200, right: 200 },
            borders: allBorders(bgColor, 0),
            children: [new Paragraph({
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text, font: "Arial", size: 22, bold: true, color: textColor })]
            })]
          })
        ]
      })
    ]
  });
}

function threeColTable(cols) {
  // cols: [{header, color, items: [{label, value}]}]
  const colW = 3120;
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [colW, colW, colW],
    rows: [
      // Header row
      new TableRow({
        children: cols.map(col =>
          new TableCell({
            width: { size: colW, type: WidthType.DXA },
            shading: { fill: col.color, type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 150, right: 150 },
            borders: allBorders(col.color, 0),
            children: [new Paragraph({
              alignment: AlignmentType.CENTER,
              children: [new TextRun({ text: col.header, font: "Arial", size: 20, bold: true, color: COLOR.white })]
            })]
          })
        )
      }),
      // Title row
      new TableRow({
        children: cols.map(col =>
          new TableCell({
            width: { size: colW, type: WidthType.DXA },
            shading: { fill: "F4F6F9", type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 60, left: 150, right: 150 },
            borders: allBorders("D6E4F0", 4),
            children: [new Paragraph({
              children: [new TextRun({ text: col.title || "", font: "Arial", size: 19, bold: true, color: col.color })]
            })]
          })
        )
      }),
      // Body rows
      ...Array.from({ length: Math.max(...cols.map(c => c.items.length)) }, (_, i) =>
        new TableRow({
          children: cols.map(col =>
            new TableCell({
              width: { size: colW, type: WidthType.DXA },
              shading: { fill: COLOR.white, type: ShadingType.CLEAR },
              margins: { top: 60, bottom: 60, left: 150, right: 150 },
              borders: allBorders("D6E4F0", 4),
              children: col.items[i] ? [new Paragraph({
                children: [new TextRun({ text: col.items[i], font: "Arial", size: 19, color: "2C3E50" })]
              })] : [new Paragraph({ children: [new TextRun("")] })]
            })
          )
        })
      )
    ]
  });
}

function twoColKV(rows, w1 = 3000, w2 = 6360) {
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [w1, w2],
    rows: rows.map((row, i) =>
      new TableRow({
        children: [
          new TableCell({
            width: { size: w1, type: WidthType.DXA },
            shading: { fill: i % 2 === 0 ? "EBF0F7" : "F4F6F9", type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 150, right: 150 },
            borders: allBorders("CCCCCC", 4),
            children: [new Paragraph({
              children: [new TextRun({ text: row[0], font: "Arial", size: 19, bold: true, color: COLOR.navy })]
            })]
          }),
          new TableCell({
            width: { size: w2, type: WidthType.DXA },
            shading: { fill: i % 2 === 0 ? "FFFFFF" : "F4F6F9", type: ShadingType.CLEAR },
            margins: { top: 80, bottom: 80, left: 150, right: 150 },
            borders: allBorders("CCCCCC", 4),
            children: [new Paragraph({
              children: [new TextRun({ text: row[1], font: "Arial", size: 19, color: "2C3E50" })]
            })]
          }),
        ]
      })
    )
  });
}

function statRow(stats) {
  // stats: [{num, label, color}]
  const w = Math.floor(9360 / stats.length);
  return new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: stats.map(() => w),
    rows: [
      new TableRow({
        children: stats.map(st =>
          new TableCell({
            width: { size: w, type: WidthType.DXA },
            shading: { fill: "F4F6F9", type: ShadingType.CLEAR },
            margins: { top: 120, bottom: 120, left: 100, right: 100 },
            borders: { top: border(st.color, 12), bottom: border("CCCCCC", 4), left: border("CCCCCC", 4), right: border("CCCCCC", 4) },
            children: [
              new Paragraph({
                alignment: AlignmentType.CENTER,
                children: [new TextRun({ text: st.num, font: "Arial", size: 40, bold: true, color: st.color })]
              }),
              new Paragraph({
                alignment: AlignmentType.CENTER,
                spacing: { before: 40 },
                children: [new TextRun({ text: st.label, font: "Arial", size: 17, color: COLOR.gray3 })]
              }),
            ]
          })
        )
      })
    ]
  });
}

// ══════════════════════════════════════════════════════════════════════════════
// DOCUMENT CONTENT
// ══════════════════════════════════════════════════════════════════════════════
const children = [];

// ── 표지 섹션 ────────────────────────────────────────────────────────────────
children.push(
  new Paragraph({ spacing: { before: 600, after: 0 }, children: [new TextRun("")] }),
  new Paragraph({
    spacing: { before: 0, after: 0 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 16, color: COLOR.teal, space: 4 } },
    children: [
      new TextRun({ text: "AX 기반 Pulse Check 체계 구축", font: "Arial", size: 52, bold: true, color: COLOR.navy, break: 0 }),
    ]
  }),
  spacer(80),
  new Paragraph({
    spacing: { before: 0, after: 240 },
    children: [new TextRun({ text: "경영진 보고서  |  BCG Situation-Complication-Resolution 구조", font: "Arial", size: 22, color: COLOR.gray3, italics: true })]
  }),
  statRow([
    { num: "연 1회", label: "현행 진단 주기", color: COLOR.red },
    { num: "월 1회", label: "Pulse Check 전환", color: COLOR.teal },
    { num: "~8주", label: "이슈 감지 선행 효과", color: COLOR.green },
    { num: "×5.7", label: "이탈 1인 예방 ROI", color: COLOR.gold },
  ]),
  spacer(120),
  twoColKV([
    ["보고 주체", "LG PRI HR실 / EXG팀"],
    ["보고 일자", "2026. 03. 10."],
    ["보고 대상", "경영진"],
    ["문서 등급", "Strictly Confidential"],
  ], 2000, 7360),
  spacer(200),
  new Paragraph({ children: [new PageBreak()] })
);

// ── 1. Executive Summary ─────────────────────────────────────────────────────
children.push(
  h1("1.  Executive Summary"),
  highlightBox(
    "핵심 메시지 : 지금 이 순간 조직에서 무슨 일이 일어나고 있는지 — HR이 먼저 알고, 경영진이 먼저 대응합니다.",
    COLOR.navy, COLOR.white
  ),
  spacer(160),
  threeColTable([
    {
      header: "Situation", color: COLOR.navy,
      title: "우리는 지금 '과거'를 보고 있습니다",
      items: [
        "LG PRI는 연 1회 LG Way Survey로 조직 건강도를 진단합니다.",
        "진단 → 분석 → 결과 공유까지 평균 6~8주가 소요됩니다.",
        "그 사이 번아웃과 이탈은 이미 진행되고 있습니다.",
      ]
    },
    {
      header: "Complication", color: COLOR.red,
      title: "실시간 이슈를 연 1회 데이터로 감지할 수 없습니다",
      items: [
        "AX 전환기 · 리더 교체기 조직 변화가 데이터에 포착되지 않습니다.",
        "이직 결정은 평균 이직 3~4개월 전에 완료됩니다. (Gallup 2024)",
        "글로벌 선도 제조사는 이미 월간 Pulse Check로 전환 중입니다.",
      ]
    },
    {
      header: "Resolution", color: COLOR.teal,
      title: "AX 기반 월간 Pulse Check로 선제 대응합니다",
      items: [
        "8개 EX 문항을 월 1회 측정, AI가 이상 신호를 자동 감지합니다.",
        "구성원 · 리더 · 경영진 각 계층에 맞춤형 Action을 제공합니다.",
        "파일럿 → 전사 확산으로 이탈 비용 연간 수억 원 절감을 기대합니다.",
      ]
    },
  ]),
  spacer(120),
  new Paragraph({ children: [new PageBreak()] })
);

// ── 2. 문제의 크기와 비용 ────────────────────────────────────────────────────
children.push(
  h1("2.  문제의 크기 : 연 1회 진단이 만들어내는 비용"),
  body("현행 LG Way Survey 체계는 세 가지 구조적 한계를 내포하고 있으며, 이는 직접적인 경영 비용으로 연결됩니다.", { italic: true }),
  spacer(80),

  h2("2-1.  현행 체계의 구조적 한계"),
  calloutBox("① Time Lag",
    "진단 → 분석 → 결과 공유까지 평균 6~8주 소요. 팀 이탈 · 번아웃이 이미 진행된 후 데이터가 도달합니다.",
    "FDECEA"),
  spacer(60),
  calloutBox("② Static Snapshot",
    "연 1회, 단 하나의 데이터 포인트. 계절 · 리더 교체 · AX 도입 충격 등 변동 요인이 전혀 반영되지 않습니다.",
    "FFF3CD"),
  spacer(60),
  calloutBox("③ Action Gap",
    "결과 리포트가 리더의 실제 행동 변화로 이어지지 않음. '좋은 데이터'가 '좋은 관리'로 자동 전환되지 않습니다.",
    "D6E4F0"),

  spacer(160),
  h2("2-2.  비용 추정 : LG PRI 규모 기준"),
  statRow([
    { num: "₩1.2억~", label: "직원 1인 이탈 시 대체 비용 추정*", color: COLOR.red },
    { num: "17%↓", label: "몰입도 하위 조직 생산성 손실 (Gallup)", color: COLOR.gold },
    { num: "43%↓", label: "몰입 상위 조직 대비 이직률 감소 (Gallup)", color: COLOR.green },
    { num: "~8주", label: "현행 이슈 감지까지 평균 소요 시간", color: COLOR.teal },
  ]),
  spacer(80),
  body("* 이탈 비용 = 채용광고 + 인터뷰 시간 + 온보딩 + 숙련도 회복 기간 인건비 합산 추정치 (연봉 1배 내외)", { italic: true, color: COLOR.gray3 }),
  spacer(80),

  h2("2-3.  이슈 감지 속도 비교 : 현행 vs. Pulse Check"),
  twoColKV([
    ["현행 (LG Way Survey)", "이슈 발생 → 평균 6~8주 후 데이터 확인 → 대응 시작까지 최대 3개월"],
    ["AX Pulse Check 전환 시", "이슈 발생 → 다음 월간 Pulse에서 즉시 포착 → 4주 이내 선제 개입 가능"],
    ["기대 효과", "이직 결정 완료 전(3~4개월) 조기 개입으로 이탈 예방 실현"],
  ]),

  spacer(120),
  new Paragraph({ children: [new PageBreak()] })
);

// ── 3. Pulse Check 해법 & Mechanism ─────────────────────────────────────────
children.push(
  h1("3.  Pulse Check 해법 : 작동 원리 (Mechanism)"),
  body("SDT(자기결정이론)와 LMX(리더-구성원 교환이론)를 심리학적 토대로 삼아, 조직의 지원과 심리적 안전이 직무 몰입을 통해 성과로 연결되는 선순환 구조를 시스템화합니다.", { italic: true }),
  spacer(80),

  h2("3-1.  이론 기반 인과 구조"),
  highlightBox("조직 지원 & 심리 안전  →  직무 몰입(Engagement)  →  조직 성과(Performance)", COLOR.teal, COLOR.white),
  spacer(80),

  h2("3-2.  3계층 측정 → 감지 → 대응 구조"),
  twoColKV([
    ["Layer 1  월간 Pulse 측정",
     "8개 EX 문항 (SDT · LMX 기반) + eNPS + 감정 온도계 / 10점 척도 + 이모지"],
    ["Layer 2  AI 이상 신호 감지",
     "트렌드 급락 자동 탐지 / NLP 기반 텍스트 감성 분석 / Risk Flag 조기 경보"],
    ["Layer 3  맞춤형 Action 제공",
     "구성원 개인 케어링 / 리더 팀 리포트 + 행동 가이드 / 경영진 Executive Dashboard"],
  ]),

  spacer(120),
  h2("3-3.  글로벌 벤치마크"),
  twoColKV([
    ["Siemens · Bosch · Toyota", "이미 분기 → 월간 Pulse 체계로 전환 완료"],
    ["Gallup 글로벌 데이터 (2024)", "몰입도 상위 조직: 생산성 +17%, 이직률 –43%"],
    ["LG그룹 타 계열사", "유사 EX 측정 체계 도입 및 운영 중 (사내 벤치마크 가능)"],
  ]),

  spacer(120),
  new Paragraph({ children: [new PageBreak()] })
);

// ── 4. 설문 설계 & 측정 체계 ──────────────────────────────────────────────────
children.push(
  h1("4.  설문 설계 & 측정 체계"),
  body("월간 8개 측정 문항 + Outcome 2개 문항으로 구성. SDT · LMX 이론을 각 문항의 심리학적 토대로 명확히 매핑합니다.", { italic: true }),
  spacer(80),

  h2("4-1.  4개 카테고리 문항 구조"),
  new Table({
    width: { size: 9360, type: WidthType.DXA },
    columnWidths: [2200, 2200, 2480, 2480],
    rows: [
      new TableRow({
        children: [
          ["카테고리", COLOR.navy],
          ["문항", COLOR.navy],
          ["이론적 근거", COLOR.navy],
          ["설계 의도", COLOR.navy],
        ].map(([text, fill]) => new TableCell({
          width: { size: text === "카테고리" ? 2200 : text === "문항" ? 2200 : 2480, type: WidthType.DXA },
          shading: { fill, type: ShadingType.CLEAR },
          margins: cellMargins,
          borders: allBorders(COLOR.navy, 4),
          children: [new Paragraph({
            children: [new TextRun({ text, font: "Arial", size: 19, bold: true, color: COLOR.white })]
          })]
        }))
      }),
      ...[
        ["A. 직무수행과 성장", "Q1 Job-Fit / 자율성", "SDT 자율성", "월별 변화에 빠르게 반응하는 선행 지표"],
